## mylib — Device Monitoring Library (nim-brokers FFI API example)
## ================================================================
## Demonstrates a realistic Nim dynamic library exposing a device
## monitoring service through C-callable interfaces generated by the
## broker FFI API system.
##
## Capabilities:
## - Add / remove / query individual devices
## - List all registered devices (returns an array of structs)
## - Receive real-time event callbacks for device status changes
##   and device discovery notifications
##
## Build (from repo root):
##   nimble buildFfiExample
##
## Produces: examples/ffiapi/nimlib/build/libmylib.{so,dylib,dll} + mylib.h

{.push raises: [].}

import brokers/[event_broker, request_broker, broker_context]

when defined(BrokerFfiApi):
  import brokers/api_library

# ---------------------------------------------------------------------------
# Shared item types (used in seq[T] result fields)
# ---------------------------------------------------------------------------

## DeviceInfo — flat struct describing a single device.
## Declared with `ApiType` so it can appear in `seq[DeviceInfo]` results.
ApiType:
  type DeviceInfo = object
    deviceId*: int64
    name*: string
    deviceType*: string
    address*: string
    online*: bool

# ---------------------------------------------------------------------------
# Request Brokers
# ---------------------------------------------------------------------------

## InitializeRequest: called after mylib_createContext() to configure the monitoring engine.
RequestBroker(API):
  type InitializeRequest = object
    configPath*: string
    initialized*: bool

  proc signature*(
    configPath: string
  ): Future[Result[InitializeRequest, string]] {.async.}

## ShutdownRequest: called by mylib_shutdown() to tear down state.
RequestBroker(API):
  type ShutdownRequest = object
    status*: int32

  proc signature*(): Future[Result[ShutdownRequest, string]] {.async.}

## AddDevice: register a new device for monitoring.
RequestBroker(API):
  type AddDevice = object
    deviceId*: int64
    success*: bool

  proc signature*(
    name: string, deviceType: string, address: string
  ): Future[Result[AddDevice, string]] {.async.}

## RemoveDevice: stop monitoring a device and remove it.
RequestBroker(API):
  type RemoveDevice = object
    success*: bool

  proc signature*(deviceId: int64): Future[Result[RemoveDevice, string]] {.async.}

## GetDevice: query a single device by ID.
RequestBroker(API):
  type GetDevice = object
    deviceId*: int64
    name*: string
    deviceType*: string
    address*: string
    online*: bool

  proc signature*(deviceId: int64): Future[Result[GetDevice, string]] {.async.}

## ListDevices: return all registered devices as an array.
RequestBroker(API):
  type ListDevices = object
    devices*: seq[DeviceInfo]

  proc signature*(): Future[Result[ListDevices, string]] {.async.}

# ---------------------------------------------------------------------------
# Event Brokers
# ---------------------------------------------------------------------------

## DeviceStatusChanged: emitted when a device's online status changes.
EventBroker(API):
  type DeviceStatusChanged = object
    deviceId*: int64
    name*: string
    online*: bool
    timestampMs*: int64

## DeviceDiscovered: emitted when auto-discovery finds a new device.
EventBroker(API):
  type DeviceDiscovered = object
    deviceId*: int64
    name*: string
    deviceType*: string
    address*: string

# ---------------------------------------------------------------------------
# Library internals (provider implementations)
# ---------------------------------------------------------------------------

type Device = object
  id: int64
  name: string
  deviceType: string
  address: string
  online: bool

var gDevices {.threadvar.}: seq[Device]
var gNextDeviceId {.threadvar.}: int64
var gConfigPath {.threadvar.}: string
var gInitialized {.threadvar.}: bool
var gProviderCtx {.threadvar.}: BrokerContext

proc nowMs(): int64 =
  int64(chronos.Moment.now().epochNanoSeconds div 1_000_000)

proc setupProviders(ctx: BrokerContext): Result[void, string] =
  ## Set up broker providers on the library's processing thread.
  gProviderCtx = ctx
  gNextDeviceId = 1
  gDevices = @[]

  # InitializeRequest provider
  let initializeProviderRes = InitializeRequest.setProvider(
    ctx,
    proc(
        configPath: string
    ): Future[Result[InitializeRequest, string]] {.closure, async.} =
      gConfigPath = configPath
      gInitialized = true
      return ok(InitializeRequest(configPath: configPath, initialized: true)),
  )
  if initializeProviderRes.isErr():
    return err(
      "failed to register InitializeRequest provider: " & initializeProviderRes.error()
    )

  # ShutdownRequest provider
  let shutdownProviderRes = ShutdownRequest.setProvider(
    ctx,
    proc(): Future[Result[ShutdownRequest, string]] {.closure, async.} =
      gInitialized = false
      gDevices = @[]
      return ok(ShutdownRequest(status: 0)),
  )
  if shutdownProviderRes.isErr():
    return
      err("failed to register ShutdownRequest provider: " & shutdownProviderRes.error())

  # AddDevice provider
  let addDeviceProviderRes = AddDevice.setProvider(
    ctx,
    proc(
        name: string, deviceType: string, address: string
    ): Future[Result[AddDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      let id = gNextDeviceId
      inc gNextDeviceId
      gDevices.add(
        Device(
          id: id, name: name, deviceType: deviceType, address: address, online: true
        )
      )
      # Emit a discovery event
      await DeviceDiscovered.emit(
        gProviderCtx,
        DeviceDiscovered(
          deviceId: id, name: name, deviceType: deviceType, address: address
        ),
      )
      return ok(AddDevice(deviceId: id, success: true)),
  )
  if addDeviceProviderRes.isErr():
    return err("failed to register AddDevice provider: " & addDeviceProviderRes.error())

  # RemoveDevice provider
  let removeDeviceProviderRes = RemoveDevice.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[RemoveDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for i in 0 ..< gDevices.len:
        if gDevices[i].id == deviceId:
          let dev = gDevices[i]
          gDevices.del(i)
          # Emit status change (offline)
          await DeviceStatusChanged.emit(
            gProviderCtx,
            DeviceStatusChanged(
              deviceId: dev.id, name: dev.name, online: false, timestampMs: nowMs()
            ),
          )
          return ok(RemoveDevice(success: true))
      return err("Device not found: " & $deviceId),
  )
  if removeDeviceProviderRes.isErr():
    return err(
      "failed to register RemoveDevice provider: " & removeDeviceProviderRes.error()
    )

  # GetDevice provider
  let getDeviceProviderRes = GetDevice.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[GetDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for dev in gDevices:
        if dev.id == deviceId:
          return ok(
            GetDevice(
              deviceId: dev.id,
              name: dev.name,
              deviceType: dev.deviceType,
              address: dev.address,
              online: dev.online,
            )
          )
      return err("Device not found: " & $deviceId),
  )
  if getDeviceProviderRes.isErr():
    return err("failed to register GetDevice provider: " & getDeviceProviderRes.error())

  # ListDevices provider
  let listDevicesProviderRes = ListDevices.setProvider(
    ctx,
    proc(): Future[Result[ListDevices, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      var infos: seq[DeviceInfo] = @[]
      for dev in gDevices:
        infos.add(
          DeviceInfo(
            deviceId: dev.id,
            name: dev.name,
            deviceType: dev.deviceType,
            address: dev.address,
            online: dev.online,
          )
        )
      return ok(ListDevices(devices: infos)),
  )
  if listDevicesProviderRes.isErr():
    return
      err("failed to register ListDevices provider: " & listDevicesProviderRes.error())

  ok()

# ---------------------------------------------------------------------------
# Library registration — MUST be last
# ---------------------------------------------------------------------------

when defined(BrokerFfiApi):
  registerBrokerLibrary:
    name:
      "mylib"
    initializeRequest:
      InitializeRequest
    shutdownRequest:
      ShutdownRequest

{.pop.}
